const n=JSON.parse('{"key":"v-f76318d2","path":"/technology/golang/go%E4%B8%8E%E5%89%8D%E7%AB%AF%E7%9A%84json%E6%95%B0%E6%8D%AE%E4%BA%A4%E4%BA%92%E7%AC%94%E8%AE%B0.html","title":"Go 与前端的 JSON 数据交互","lang":"zh-CN","frontmatter":{"icon":"edit","date":"2023-01-01T00:00:00.000Z","category":["golang"],"tag":["go"],"description":"Go 与前端的 JSON 数据交互 golang处理json数据 encoding/json包中的json.Unmarshal与json.Marshal json.Unmarshal:解析json的byte类型数据，转换成结构体对象 json.Marshal:将结构体对象转换成json的byte类型数据 type Message struct { \\t//后面的json字段与需要对应的json格式的字段一致,不一致则json与结构体对象无法互相转换 \\t//例：{\\"address\\":\\"127.0.0.1:40000\\"，\\"body\\":\\"1234\\"} \\t \\tAddress string `json:\\"address\\"` \\tBody string `json:\\"body\\"` } //（a *App）是使用wails的要求，可以无视 func (a *App) NewConnection(Msg string) string { \\t//接收前端json字符串Msg \\tfmt.Println(\\"字符串\\", Msg) \\t//结构体对象 mes \\tvar mes Message \\t//将json字符串解析，Unmarshal解析需要先将json数据转为[]byte类型，返回值是错误类型 \\t//解析后转换成结构体对象mes \\terr := json.Unmarshal([]byte(Msg), &amp;mes) \\tif err != nil { \\t\\tprintln(\\"ERROR:\\", err) \\t} \\tfmt.Println(\\"ERROR\\", err) \\tfmt.Println(\\"接收json\\", mes.Address) \\t \\tmes.Address = \\"111\\" \\tmes.Body = \\"222\\" //Marshal将对象转换成json，返回[]byte和error \\tmesJson, _ := json.Marshal(mes) \\tfmt.Println(\\"转换json\\", string(mesJson)) //返回json字符串 \\treturn string(mesJson) }","head":[["meta",{"property":"og:url","content":"https://foldleaf.github.io/leaf-hope/leaf-hope/technology/golang/go%E4%B8%8E%E5%89%8D%E7%AB%AF%E7%9A%84json%E6%95%B0%E6%8D%AE%E4%BA%A4%E4%BA%92%E7%AC%94%E8%AE%B0.html"}],["meta",{"property":"og:site_name","content":"foldleaf的个人博客"}],["meta",{"property":"og:title","content":"Go 与前端的 JSON 数据交互"}],["meta",{"property":"og:description","content":"Go 与前端的 JSON 数据交互 golang处理json数据 encoding/json包中的json.Unmarshal与json.Marshal json.Unmarshal:解析json的byte类型数据，转换成结构体对象 json.Marshal:将结构体对象转换成json的byte类型数据 type Message struct { \\t//后面的json字段与需要对应的json格式的字段一致,不一致则json与结构体对象无法互相转换 \\t//例：{\\"address\\":\\"127.0.0.1:40000\\"，\\"body\\":\\"1234\\"} \\t \\tAddress string `json:\\"address\\"` \\tBody string `json:\\"body\\"` } //（a *App）是使用wails的要求，可以无视 func (a *App) NewConnection(Msg string) string { \\t//接收前端json字符串Msg \\tfmt.Println(\\"字符串\\", Msg) \\t//结构体对象 mes \\tvar mes Message \\t//将json字符串解析，Unmarshal解析需要先将json数据转为[]byte类型，返回值是错误类型 \\t//解析后转换成结构体对象mes \\terr := json.Unmarshal([]byte(Msg), &amp;mes) \\tif err != nil { \\t\\tprintln(\\"ERROR:\\", err) \\t} \\tfmt.Println(\\"ERROR\\", err) \\tfmt.Println(\\"接收json\\", mes.Address) \\t \\tmes.Address = \\"111\\" \\tmes.Body = \\"222\\" //Marshal将对象转换成json，返回[]byte和error \\tmesJson, _ := json.Marshal(mes) \\tfmt.Println(\\"转换json\\", string(mesJson)) //返回json字符串 \\treturn string(mesJson) }"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"article:tag","content":"go"}],["meta",{"property":"article:published_time","content":"2023-01-01T00:00:00.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Go 与前端的 JSON 数据交互\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2023-01-01T00:00:00.000Z\\",\\"dateModified\\":null,\\"author\\":[]}"]]},"headers":[],"git":{},"readingTime":{"minutes":1.93,"words":579},"filePathRelative":"technology/golang/go与前端的json数据交互笔记.md","localizedDate":"2023年1月1日","excerpt":"<h1> Go 与前端的 JSON 数据交互</h1>\\n<p>golang处理json数据\\n<code>encoding/json</code>包中的<code>json.Unmarshal</code>与<code>json.Marshal</code>\\n<code>json.Unmarshal</code>:解析json的byte类型数据，转换成结构体对象\\n<code>json.Marshal</code>:将结构体对象转换成json的byte类型数据</p>\\n<div class=\\"language-go line-numbers-mode\\" data-ext=\\"go\\"><pre class=\\"language-go\\"><code><span class=\\"token keyword\\">type</span> Message <span class=\\"token keyword\\">struct</span> <span class=\\"token punctuation\\">{</span>\\n\\t<span class=\\"token comment\\">//后面的json字段与需要对应的json格式的字段一致,不一致则json与结构体对象无法互相转换</span>\\n\\t<span class=\\"token comment\\">//例：{\\"address\\":\\"127.0.0.1:40000\\"，\\"body\\":\\"1234\\"}</span>\\n\\t\\n\\tAddress <span class=\\"token builtin\\">string</span> <span class=\\"token string\\">`json:\\"address\\"`</span>\\n\\tBody    <span class=\\"token builtin\\">string</span> <span class=\\"token string\\">`json:\\"body\\"`</span>\\n<span class=\\"token punctuation\\">}</span>\\n<span class=\\"token comment\\">//（a *App）是使用wails的要求，可以无视</span>\\n<span class=\\"token keyword\\">func</span> <span class=\\"token punctuation\\">(</span>a <span class=\\"token operator\\">*</span>App<span class=\\"token punctuation\\">)</span> <span class=\\"token function\\">NewConnection</span><span class=\\"token punctuation\\">(</span>Msg <span class=\\"token builtin\\">string</span><span class=\\"token punctuation\\">)</span> <span class=\\"token builtin\\">string</span> <span class=\\"token punctuation\\">{</span>\\n\\t<span class=\\"token comment\\">//接收前端json字符串Msg</span>\\n\\tfmt<span class=\\"token punctuation\\">.</span><span class=\\"token function\\">Println</span><span class=\\"token punctuation\\">(</span><span class=\\"token string\\">\\"字符串\\"</span><span class=\\"token punctuation\\">,</span> Msg<span class=\\"token punctuation\\">)</span>\\n\\t<span class=\\"token comment\\">//结构体对象 mes</span>\\n\\t<span class=\\"token keyword\\">var</span> mes Message\\n\\t<span class=\\"token comment\\">//将json字符串解析，Unmarshal解析需要先将json数据转为[]byte类型，返回值是错误类型</span>\\n\\t<span class=\\"token comment\\">//解析后转换成结构体对象mes</span>\\n\\terr <span class=\\"token operator\\">:=</span> json<span class=\\"token punctuation\\">.</span><span class=\\"token function\\">Unmarshal</span><span class=\\"token punctuation\\">(</span><span class=\\"token punctuation\\">[</span><span class=\\"token punctuation\\">]</span><span class=\\"token function\\">byte</span><span class=\\"token punctuation\\">(</span>Msg<span class=\\"token punctuation\\">)</span><span class=\\"token punctuation\\">,</span> <span class=\\"token operator\\">&amp;</span>mes<span class=\\"token punctuation\\">)</span>\\n\\t<span class=\\"token keyword\\">if</span> err <span class=\\"token operator\\">!=</span> <span class=\\"token boolean\\">nil</span> <span class=\\"token punctuation\\">{</span>\\n\\t\\t<span class=\\"token function\\">println</span><span class=\\"token punctuation\\">(</span><span class=\\"token string\\">\\"ERROR:\\"</span><span class=\\"token punctuation\\">,</span> err<span class=\\"token punctuation\\">)</span>\\n\\t<span class=\\"token punctuation\\">}</span>\\n\\tfmt<span class=\\"token punctuation\\">.</span><span class=\\"token function\\">Println</span><span class=\\"token punctuation\\">(</span><span class=\\"token string\\">\\"ERROR\\"</span><span class=\\"token punctuation\\">,</span> err<span class=\\"token punctuation\\">)</span>\\n\\tfmt<span class=\\"token punctuation\\">.</span><span class=\\"token function\\">Println</span><span class=\\"token punctuation\\">(</span><span class=\\"token string\\">\\"接收json\\"</span><span class=\\"token punctuation\\">,</span> mes<span class=\\"token punctuation\\">.</span>Address<span class=\\"token punctuation\\">)</span>\\n\\t\\n\\tmes<span class=\\"token punctuation\\">.</span>Address <span class=\\"token operator\\">=</span> <span class=\\"token string\\">\\"111\\"</span>\\n\\tmes<span class=\\"token punctuation\\">.</span>Body <span class=\\"token operator\\">=</span> <span class=\\"token string\\">\\"222\\"</span>\\n    <span class=\\"token comment\\">//Marshal将对象转换成json，返回[]byte和error</span>\\n\\tmesJson<span class=\\"token punctuation\\">,</span> <span class=\\"token boolean\\">_</span> <span class=\\"token operator\\">:=</span> json<span class=\\"token punctuation\\">.</span><span class=\\"token function\\">Marshal</span><span class=\\"token punctuation\\">(</span>mes<span class=\\"token punctuation\\">)</span> \\n\\tfmt<span class=\\"token punctuation\\">.</span><span class=\\"token function\\">Println</span><span class=\\"token punctuation\\">(</span><span class=\\"token string\\">\\"转换json\\"</span><span class=\\"token punctuation\\">,</span> <span class=\\"token function\\">string</span><span class=\\"token punctuation\\">(</span>mesJson<span class=\\"token punctuation\\">)</span><span class=\\"token punctuation\\">)</span>\\n    <span class=\\"token comment\\">//返回json字符串</span>\\n\\t<span class=\\"token keyword\\">return</span> <span class=\\"token function\\">string</span><span class=\\"token punctuation\\">(</span>mesJson<span class=\\"token punctuation\\">)</span>\\n\\n<span class=\\"token punctuation\\">}</span>\\n</code></pre><div class=\\"line-numbers\\" aria-hidden=\\"true\\"><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div></div></div>","autoDesc":true}');export{n as data};
